    for (const name in table.players) {
      let pl = table.players[name];
      pl.score = 0;
    }
    fen.cards = [1, 2, 3];
    fen.deck = range(4, table.options.numCards);
    table.plorder = jsCopy(table.playerNames);
    table.turn = jsCopy(table.playerNames);
