function entityToUnicode(entity) {
  const div = document.createElement("div");
  div.innerHTML = entity;
  return div.textContent;
}
function entityToUnicodeEscape(entity) {
  let num;
  if (entity.toLowerCase().startsWith("&#x")) {
    num = parseInt(entity.replace(/[&#x;]/gi, ""), 16);
  } else {
    num = parseInt(entity.replace(/[&#;]/g, ""), 10);
  }
  if (num <= 0xFFFF) {
    return "\\u" + num.toString(16).padStart(4, "0");
  } else {
    return "\\u{" + num.toString(16) + "}";
  }
}
function entityToUnicodePlain(entity) {
  let num;
  if (entity.toLowerCase().startsWith("&#x")) {
    num = parseInt(entity.replace(/[&#x;]/gi, ""), 16);
  } else {
    num = parseInt(entity.replace(/[&#;]/g, ""), 10);
  }
  return "u" + num.toString(16).toUpperCase();
}
