function fitFont(text, fz = 20, w2 = 200, h2 = 100) {
  let e1, e2, r1, r2;
  e1 = mDiv(dTable, { w: w2, h: h2, display: 'inline-block' });
  do {
    e2 = mDiv(e1, { fz: fz, display: 'inline-block' }, null, text);
    r1 = getRect(e1);
    r2 = getRect(e2);
    e2.remove();
    fz -= 1;
  } while (r1.w * r1.h < r2.w * r2.h);
  e1.remove();
  return [fz + 1, r2.w, r2.h];
}
function fitFzToBox(div, maxWidth, maxHeight, options = {}) {
  const {
    minFontSize = 10,
    maxFontSize = 100,
    fontStep = 1,
    lineHeight = 1
  } = options;
  const style = window.getComputedStyle(div);
  const originalText = div.textContent;
  const testDiv = document.createElement("div");
  document.body.appendChild(testDiv);
  testDiv.style.position = "absolute";
  testDiv.style.visibility = "hidden";
  testDiv.style.whiteSpace = "pre-wrap";
  testDiv.style.wordBreak = "break-word";
  const keysToCopy = ["fontFamily", "fontWeight", "fontStyle", "letterSpacing", "padding", "border"];
  keysToCopy.forEach(key => {
    testDiv.style[key] = style[key];
  });
  let fontSize = maxFontSize;
  testDiv.textContent = originalText;
  while (fontSize >= minFontSize) {
    testDiv.style.fontSize = `${fontSize}px`;
    testDiv.style.lineHeight = lineHeight;
    if (
      testDiv.offsetWidth <= maxWidth &&
      testDiv.offsetHeight <= maxHeight
    ) {
      break;
    }
    fontSize -= fontStep;
  }
  div.style.fontSize = `${fontSize}px`;
  div.style.lineHeight = lineHeight;
  document.body.removeChild(testDiv);
  return fontSize;
}
function fitSvg(el) {
  const box = el.querySelector('text').getBBox();
  el.style.width = `${box.width}px`;
  el.style.height = `${box.height}px`;
}
function fitTextToBox(text, family, maxWidth, maxHeight, options = {}) {
  const {
    minFontSize = 10,
    maxFontSize = 100,
    fontStep = 1,
    lineHeight = 1.2,
    weight = "normal",
    fontStyle = "normal",
    letterSpacing = "normal",
    padding = "0"
  } = options;
  const testDiv = mDom(document.body, {}, { tag: 'div', html: text });
  mStyle(testDiv, {
    position: 'absolute',
    visibility: 'hidden',
    whiteSpace: 'pre-wrap',
    wordBreak: 'break-word',
    padding,
    family,
    weight,
    fontStyle,
    letterSpacing
  });
  let fz = maxFontSize;
  while (fz >= minFontSize) {
    mStyle(testDiv, { fz, lineHeight });
    if (testDiv.offsetWidth <= maxWidth && testDiv.offsetHeight <= maxHeight) break;
    fz -= fontStep;
  }
  testDiv.remove();
  return fz;
}
