function grayShades(n) {
  const shades = [];
  for (let i = 0; i < n; i++) {
    const v = Math.round(255 - (i * 255 / (n - 1)));
    const hex = v.toString(16).padStart(2, '0');
    shades.push(`#${hex}${hex}${hex}`);
  }
  return shades;
}
function groupByProperty(list, prop) {
  const groups = {};
  list.forEach(obj => {
    const key = obj[prop];
    if (!groups[key]) {
      groups[key] = [];
    }
    groups[key].push(obj);
  });
  return Object.values(groups);
}
