function ignoreDoubleClick(el, handler, delay = 400) {
  let lastClickTime = 0;
  el.addEventListener("click", e => {
    const now = Date.now();
    if (now - lastClickTime < delay) {
      e.stopImmediatePropagation();
      e.preventDefault();
      return;
    }
    lastClickTime = now;
    handler(e);
  });
}
