    document.getElementById('label').style.display = 'none';
    uploadBtn.style.display = 'inline-block';
    cancelBtn.style.display = 'inline-block';
    imageEl.src = src;
    imageEl.onload = () => {
      if (cropper) cropper.destroy();
      cropper = new Cropper(imageEl, {
        aspectRatio: 1,
        viewMode: 1,
        autoCropArea: 0.8,
        zoomable: true,
        movable: true,
      });
    };
