function nextBar(ctx, rest, color) {
  list = rest;
  let val = findMostFrequentVal(list, 'x');
  rest = list.filter(p => !isWithinDelta(p.x, val, 2));
  let line = getBar(ctx, list, val);
  line.map(p => drawPix(ctx, p.x, p.y, color));
  return { val, line, rest, color };
}
function nextLine(ctx, rest, color) {
  list = rest;
  let val = findMostFrequentVal(list, 'y');
  rest = list.filter(p => !isWithinDelta(p.y, val, 2));
  let line = getLine(ctx, list, val);
  if (line) line.map(p => drawPix(ctx, p.x, p.y, color));
  return { val, line, rest, color };
}
function nope0(s) {
  let parts = s.split(' d=');
  let res = parts[0];
  for (let i = 1; i < parts.length; i++) {
    let ch = parts[i][0];
    let p = parts[i].slice(1);
    let ndata = ch == '"' ? stringBefore(p, '"') : stringBefore(p, "'");
    let ydata = p.slice(ndata.length);
    res += ' d=' + ch + '[' + ndata.length + ']' + ch + ydata;
  }
  return res;
}
function normalSegmentThroughMidpoint(x1, y1, x2, y2, length) {
  const mx = (x1 + x2) / 2;
  const my = (y1 + y2) / 2;
  const dx = x2 - x1;
  const dy = y2 - y1;
  let nx = -dy;
  let ny = dx;
  const norm = Math.hypot(nx, ny);
  if (norm === 0) {
    throw new Error("The two points are identical; cannot compute a normal.");
  }
  nx /= norm;
  ny /= norm;
  const halfLen = length / 2;
  const xA = mx + nx * halfLen;
  const yA = my + ny * halfLen;
  const xB = mx - nx * halfLen;
  const yB = my - ny * halfLen;
  return [
    { x: xA, y: yA },
    { x: xB, y: yB }
  ];
}
function normalThroughMidpoint(x1, y1, x2, y2) {
  const mx = (x1 + x2) / 2;
  const my = (y1 + y2) / 2;
  const dx = x2 - x1;
  const dy = y2 - y1;
  let slope, normalSlope, intercept;
  if (dx === 0) {
    normalSlope = 0;
    intercept = my;
  } else if (dy === 0) {
    normalSlope = Infinity;
    intercept = mx;
  } else {
    const originalSlope = dy / dx;
    normalSlope = -1 / originalSlope;
    intercept = my - normalSlope * mx;
  }
  return {
    midpoint: { x: mx, y: my },
    normalLine: {
      slope: normalSlope,
      intercept: intercept,
      form: normalSlope === Infinity
        ? `x = ${intercept}`
        : `y = ${normalSlope}x + ${intercept}`
    }
  };
}
function normalizeString(s, opts = {}) {
  let sep = valf(opts.sep, '_');
  let keep = valf(opts.keep, []);
  let lowercase = isdef(opts.lowercase) ? opts.lowercase : true;
  s = lowercase ? s.toLowerCase().trim() : s.trim();
  let res = '';
  for (let i = 0; i < s.length; i++) { if (isAlphaNum(s[i]) || keep.includes(s[i])) res += s[i]; else if (last(res) != sep) res += sep; }
  return res;
}
function normalize_bid(bid) {
  let need_to_sort = bid[0] == '_' && bid[2] != '_'
    || bid[2] != '_' && bid[2] > bid[0]
    || bid[2] == bid[0] && is_higher_ranked_name(bid[3], bid[1]);
  if (need_to_sort) {
    let [h0, h1] = [bid[0], bid[1]];
    [bid[0], bid[1]] = [bid[2], bid[3]];
    [bid[2], bid[3]] = [h0, h1];
  }
  return bid;
}
function normalize_string(s, sep = '_') {
  s = s.toLowerCase().trim();
  let res = '';
  for (let i = 0; i < s.length; i++) { if (isAlphaNum(s[i])) res += s[i]; else if (s[i] == ' ') res += sep; }
  return res;
}
function nundef(x) { return x === null || x === undefined; }
function object2string(o, props = [], except_props = []) {
  let s = '';
  if (nundef(o)) return s;
  if (isString(o)) return o;
  let keys = Object.keys(o).sort();
  for (const k of keys) {
    if (!isEmpty(props) && props.includes(k) || !except_props.includes(k)) {
      let val = isList(o[k]) ? o[k].join(',') : isDict(o[k]) ? object2string(o[k].props, except_props) : o[k];
      let key_part = isEmpty(s) ? '' : `, ${k}:`;
      s += val;
    }
  }
  return s;
}
