function parseEmojiTable(tableElement) {
  const rows = tableElement.querySelectorAll("tr");
  const results = [];
  rows.forEach(tr => {
    const tds = tr.querySelectorAll("td");
    if (tds.length < 10) return;
    const pngs = [
      tds[0].querySelector("img")?.src || null,
      tds[1].querySelector("img")?.src || null,
      tds[2].querySelector("img")?.src || null,
    ];
    const dash = tds[3].textContent.trim();
    const emoji = tds[4].textContent.trim();
    const name = tds[5].textContent.trim();
    const shortcode = tds[6].textContent.trim();
    const unicodeText = tds[7].textContent.trim();
    const pngName = tds[8].textContent.trim();
    const position = tds[9].textContent.trim();
    const codepoints = unicodeText
      .split(/\s+/)
      .map(s => s.replace("U+", "").toLowerCase());
    results.push({
      pngs,
      emoji,
      name,
      shortcode,
      codepoints,
      pngName,
      position
    });
  });
  return results;
}
