function pentagonTessellationCenters(rows, cols, w, h) {
  const centers = [];
  for (let r = 0; r < rows; r++) {
    const y = r * h;
    const xOffset = (r % 2) * (w / 2);
    for (let c = 0; c < cols; c++) {
      const x = c * w + xOffset;
      centers.push({ x, y });
    }
  }
  return centers;
}
