function post_visit() {
  let [fen, A, uplayer, building, obuilding, owner] = [Z.fen, Z.A, Z.uplayer, Z.A.building, Z.A.obuilding, Z.A.buildingowner];
  let buildingtype = Z.A.building.o.type;
  let res = A.selected[0] == 0; 
  if (!res) {
    if (fen.players[owner].coins > 0) {
      fen.players[owner].coins -= 1;
      fen.players[uplayer].coins += 1;
    }
  } else {
    let list = obuilding.list;
    let correct_key = list[0];
    let rank = correct_key[0];
    while (list.length > 0) {
      let ckey = list[0];
      if (ckey[0] != rank) {
        elem_from_to_top(ckey, list, fen.deck_discard);
      } else {
        elem_from_to(ckey, list, fen.players[owner].hand);
      }
    }
    if (isdef(obuilding.h)) {
      fen.deck_discard.unshift(obuilding.h);
    }
    ari_reorg_discard(fen);
    let blist = lookup(fen, stringBeforeLast(building.path, '.').split('.')); //building.path.split('.')); //stringBeforeLast(ibuilding.path, '.').split('.'));, stringBeforeLast(building.path, '.').split('.'));
    removeInPlace(blist, obuilding);
  }
  ari_history_list([`${uplayer} visited ${buildingtype} of ${owner} resulting in ${res ? 'destruction' : 'payoff'}`,], 'visit');
  ari_next_action(fen, uplayer);
}
function precomputePolygonNeighbors(groupElement) {
  if (!groupElement || !(groupElement instanceof SVGGElement)) {
    console.error("Invalid group element.");
    return;
  }
  const polygons = Array.from(groupElement.querySelectorAll('polygon'));
  polygons.forEach((polygon, i) => {
    if (!polygon.id) {
      polygon.id = `poly-${i}`;
    }
  });
  function getPointSet(polygon) {
    return new Set(
      polygon.getAttribute('points')
        .trim()
        .split(/\s+/)
        .map(p => p.trim())
    );
  }
  const pointSets = new Map();
  polygons.forEach(p => {
    pointSets.set(p.id, getPointSet(p));
  });
  polygons.forEach(p1 => {
    const id1 = p1.id;
    const set1 = pointSets.get(id1);
    const neighbors = [];
    polygons.forEach(p2 => {
      const id2 = p2.id;
      if (id1 === id2) return;
      const set2 = pointSets.get(id2);
      const shared = [...set1].filter(point => set2.has(point));
      if (shared.length >= 2) {
        neighbors.push(id2);
      }
    });
    p1.dataset.neighbors = neighbors.join(',');
  });
}
function precomputePolygonNeighborsFromSvg(groupElement) {
  if (!groupElement || !(groupElement instanceof SVGGElement)) {
    console.error("Invalid group element.");
    return;
  }
  const polygons = Array.from(groupElement.querySelectorAll('polygon'));
  let nei = {};
  polygons.forEach((polygon, i) => {
    if (!polygon.id) {
      polygon.id = `poly-${i}`;
      nei[i] = [];
    }
  });
  function getPointSet(polygon) {
    return new Set(
      polygon.getAttribute('points')
        .trim()
        .split(/\s+/)
        .map(p => p.trim())
    );
  }
  const pointSets = new Map();
  polygons.forEach(p => {
    pointSets.set(p.id, getPointSet(p));
  });
  polygons.forEach(p1 => {
    const id1 = p1.id;
    const set1 = pointSets.get(id1);
    const neighbors = [];
    polygons.forEach(p2 => {
      const id2 = p2.id;
      if (id1 === id2) return;
      const set2 = pointSets.get(id2);
      const shared = [...set1].filter(point => set2.has(point));
      if (shared.length >= 2) {
        neighbors.push(id2);
      }
    });
    let i = Number(id1.split('-')[1]);
    nei[i] = neighbors.map(x => Number(x.split('-')[1]));
    p1.dataset.neighbors = neighbors.join(',');
  });
  return nei;
}
async function preloadImages(imageUrls) {
  const promises = imageUrls.map(async (url) => {
    const img = new Image();
    return new Promise((resolve, reject) => {
      img.onload = () => resolve(img);
      img.onerror = (error) => reject(error);
      img.src = url;
    });
  });
  return await Promise.all(promises);
}
