function testCartesianFunctions() {
  const data = [
    { x: "a", y: 1 },
    { x: "a", y: 2 },
    { x: "b", y: 1 },
    { x: "b", y: 2 }
  ];
  const [keys, compact] = cartesianContract(data);
  const expanded = cartesianExpand(keys, compact);
  return {
    compact: [keys, compact],
    expanded: expanded
  };
}
