function triangleTessellationCenters(rows, cols, w, h) {
  const centers = [];
  for (let r = 0; r < rows; r++) {
    const baseY = r * h;
    let x = 0;
    for (let c = 0; c < cols; c++) {
      const isUp = (r + c) % 2 === 0;
      const y = baseY;
      centers.push({ x, y, up: isUp });
      x = x + w / 2;
    }
  }
  return centers;
}
