function wsSetup(table) {
  let fen = {};
  fen.deck = jsCopy(M.byCollection.tierspiel).map(x => wsGenerateCardInfo(x));
  arrShuffle(fen.deck);
  for (const name in table.players) {
    let pl = table.players[name];
    pl.score = 0;
    pl.cards = deckDeal(fen.deck, 5);
    pl.missions = [];
    pl.offsprings = 0;
    wsGetFoodlist().map(x => pl[x] = 0);
    pl.forest = [];
    pl.grassland = [];
    pl.wetland = [];
  }
  fen.round = 0;
  fen.phase = 'init';
  fen.stage = 'pick_cards';
  table.plorder = jsCopy(Object.keys(table.players));
  table.turn = jsCopy(Object.keys(table.players));
  return fen;
}
